 11→struct PersonalTrainerView: View {
 12→    @Environment(AppRouter.self) private var router
 13→    @Environment(\.dependencyResolver) private var resolver
 14→
 15→    @State private var viewModel: PersonalTrainerViewModel
 16→    @State private var showSearchSheet = false
 17→    private let initialTab: TrainerDashboardTab
 18→
 19→    init(resolver: Resolver, initialTab: TrainerDashboardTab = .today) {
 20→        _viewModel = State(wrappedValue: PersonalTrainerViewModel(resolver: resolver))
 21→        self.initialTab = initialTab
 22→    }
 23→
 24→    var body: some View {
 25→        Group {
 26→            if viewModel.isLoading && viewModel.currentTrainer == nil {
 27→                ScrollView {
 28→                    loadingView.padding()
 29→                }
 30→            } else if !viewModel.isFeatureEnabled {
 31→                ScrollView {
 32→                    featureDisabledView.padding()
 33→                }
 34→            } else if viewModel.hasTrainer, let trainer = viewModel.currentTrainer, viewModel.isConnected {
 35→                TrainerDashboardView(
 36→                    trainer: trainer,
 37→                    workouts: viewModel.assignedWorkouts,
 38→                    isChatEnabled: viewModel.isChatEnabled,
 39→                    onDisconnect: {
 40→                        Task { await viewModel.cancelConnection() }
 41→                    },
 42→                    currentUserId: viewModel.currentUserId,
 43→                    resolver: resolver,
 44→                    initialTab: initialTab
 45→                )
 46→            } else if !viewModel.hasTrainer {
 47→                TrainerListView(viewModel: viewModel) { trainer in
 48→                    viewModel.selectedTrainer = trainer
 49→                    viewModel.showConnectionSheet = true
 50→                }
 51→            } else {
 52→                ScrollView {
 53→                    VStack(spacing: FitTodaySpacing.lg) {
 54→                        connectedTrainerSection
 55→                    }
 56→                    .padding()
 57→                }
 58→            }
 59→        }
 60→        .background(FitTodayColor.background.ignoresSafeArea())
 61→        .navigationTitle("personal_trainer.title".localized)
 62→        .onAppear {
 63→            viewModel.onAppear()
 64→        }
 65→        .onDisappear {
 66→            viewModel.onDisappear()
 67→        }
 68→        .sheet(isPresented: $showSearchSheet) {
 69→            TrainerSearchView(viewModel: viewModel)
 70→        }
 71→        .sheet(isPresented: $viewModel.showConnectionSheet) {
 72→            if let trainer = viewModel.selectedTrainer {
 73→                ConnectionRequestSheet(
 74→                    trainer: trainer,
 75→                    isRequesting: viewModel.isRequestingConnection,
 76→                    onConfirm: {
 77→                        Task {
 78→                            let success = await viewModel.requestConnection(to: trainer)
 79→                            if success {
 80→                                showSearchSheet = false
 81→                            }
 82→                        }
 83→                    },
 84→                    onCancel: {
 85→                        viewModel.dismissConnectionSheet()
 86→                    }
 87→                )
 88→                .presentationDetents([.medium, .large])
 89→            }
 90→        }
 91→        .alert(
 92→            "personal_trainer.error.title".localized,
 93→            isPresented: Binding(
 94→                get: { viewModel.error != nil },
 95→                set: { if !$0 { viewModel.clearError() } }
 96→            )
 97→        ) {
 98→            Button("Ok", role: .cancel) {
 99→                viewModel.clearError()
100→            }
101→        } message: {
102→            Text(viewModel.error?.localizedDescription ?? "personal_trainer.error.default".localized)
103→        }
104→    }
105→
106→    // MARK: - Loading View
107→
