109→        VStack(spacing: FitTodaySpacing.md) {
110→            ProgressView()
111→                .tint(FitTodayColor.brandPrimary)
112→            Text("personal_trainer.loading".localized)
113→                .font(FitTodayFont.ui(size: 14, weight: .medium))
114→                .foregroundStyle(FitTodayColor.textSecondary)
