188→                                await viewModel.findByInviteCode()
189→                            }
190→                        } label: {
191→                            if viewModel.isSearching {
192→                                ProgressView()
193→                                    .tint(.white)
194→                            } else {
195→                                Text("personal_trainer.invite.use_button".localized)
196→                            }
197→                        }
198→                        .fitPrimaryStyle()
199→                        .disabled(!viewModel.canUseInviteCode || viewModel.isSearching)
200→                    }
201→                }
202→            }
203→
204→            // Benefits
205→            benefitsSection
206→        }
207→    }
