209→    // MARK: - Benefits Section
210→
211→    private var benefitsSection: some View {
212→        VStack(alignment: .leading, spacing: FitTodaySpacing.md) {
213→            Text("personal_trainer.benefits.title".localized)
214→                .font(FitTodayFont.ui(size: 18, weight: .bold))
215→                .foregroundStyle(FitTodayColor.textPrimary)
216→
217→            benefitRow(icon: "dumbbell.fill", title: "personal_trainer.benefits.workouts.title".localized, description: "personal_trainer.benefits.workouts.description".localized)
218→
219→            benefitRow(icon: "chart.line.uptrend.xyaxis", title: "personal_trainer.benefits.tracking.title".localized, description: "personal_trainer.benefits.tracking.description".localized)
