  8→import SwiftUI
  9→
 10→struct TrainerSearchView: View {
 11→    @Environment(\.dismiss) private var dismiss
 12→    @Bindable var viewModel: PersonalTrainerViewModel
 13→
 14→    @State private var searchDebounceTask: Task<Void, Never>?
 15→    @FocusState private var isSearchFocused: Bool
 16→
 17→    var body: some View {
 18→        NavigationStack {
 19→            VStack(spacing: 0) {
 20→                // Search Header
 21→                searchHeader
 22→
 23→                Divider()
 24→                    .background(FitTodayColor.outline)
 25→
 26→                // Content
 27→                ScrollView {
 28→                    VStack(spacing: FitTodaySpacing.lg) {
 29→                        // Invite Code Section
 30→                        inviteCodeSection
 31→
 32→                        // Search Results
 33→                        if viewModel.isSearching {
 34→                            searchingView
 35→                        } else if !viewModel.searchResults.isEmpty {
 36→                            searchResultsSection
 37→                        } else if !viewModel.searchQuery.isEmpty {
 38→                            noResultsView
 39→                        } else {
 40→                            searchPromptView
 41→                        }
 42→                    }
 43→                    .padding()
 44→                }
 45→            }
 46→            .background(FitTodayColor.background.ignoresSafeArea())
 47→            .navigationTitle("personal_trainer.search.title".localized)
 48→            .navigationBarTitleDisplayMode(.inline)
 49→            .toolbar {
 50→                ToolbarItem(placement: .topBarLeading) {
 51→                    Button("common.cancel".localized) {
 52→                        dismiss()
 53→                    }
 54→                    .foregroundStyle(FitTodayColor.textSecondary)
 55→                }
 56→            }
 57→            .onAppear {
 58→                isSearchFocused = true
 59→            }
 60→        }
 61→    }
 62→
 63→    // MARK: - Search Header
 64→
 65→    private var searchHeader: some View {
 66→        VStack(spacing: FitTodaySpacing.md) {
 67→            HStack(spacing: FitTodaySpacing.sm) {
 68→                Image(systemName: "magnifyingglass")
 69→                    .foregroundStyle(FitTodayColor.textSecondary)
 70→
 71→                TextField("personal_trainer.search.placeholder".localized, text: $viewModel.searchQuery)
 72→                    .textFieldStyle(.plain)
 73→                    .autocorrectionDisabled()
 74→                    .focused($isSearchFocused)
 75→                    .onChange(of: viewModel.searchQuery) { _, newValue in
 76→                        debounceSearch(query: newValue)
 77→                    }
 78→
 79→                if !viewModel.searchQuery.isEmpty {
 80→                    Button {
 81→                        viewModel.clearSearch()
 82→                    } label: {
 83→                        Image(systemName: "xmark.circle.fill")
 84→                            .foregroundStyle(FitTodayColor.textSecondary)
 85→                    }
 86→                }
 87→            }
 88→            .padding()
 89→            .background(FitTodayColor.surface)
 90→            .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
 91→        }
 92→        .padding()
 93→    }
 94→
 95→    // MARK: - Invite Code Section
 96→
 97→    private var inviteCodeSection: some View {
 98→        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
 99→            Text("personal_trainer.search.invite_code".localized)
100→                .font(FitTodayFont.ui(size: 14, weight: .semiBold))
101→                .foregroundStyle(FitTodayColor.textSecondary)
102→
103→            HStack(spacing: FitTodaySpacing.sm) {
104→                TextField("personal_trainer.search.invite_input".localized, text: $viewModel.inviteCode)
105→                    .textFieldStyle(.roundedBorder)
106→                    .textCase(.uppercase)
107→                    .autocorrectionDisabled()
108→
109→                Button {
110→                    Task {
111→                        await viewModel.findByInviteCode()
112→                    }
113→                } label: {
114→                    if viewModel.isSearching && !viewModel.inviteCode.isEmpty {
115→                        ProgressView()
116→                            .tint(.white)
117→                            .frame(width: 60)
118→                    } else {
119→                        Text("personal_trainer.search.find_button".localized)
120→                            .frame(width: 60)
