164→// MARK: - Get Current Trainer Use Case
165→
166→protocol GetCurrentTrainerUseCaseProtocol: Sendable {
167→    func execute() async throws -> (trainer: PersonalTrainer, relationship: TrainerStudentRelationship)?
168→    func observeRelationship() -> AsyncStream<TrainerStudentRelationship?>
169→}
170→
171→final class GetCurrentTrainerUseCase: GetCurrentTrainerUseCaseProtocol, @unchecked Sendable {
172→    private let trainerRepository: PersonalTrainerRepository
173→    private let trainerStudentRepository: TrainerStudentRepository
174→    private let authRepository: AuthenticationRepository
175→    private let featureFlagChecker: FeatureFlagChecking
176→
177→    init(
178→        trainerRepository: PersonalTrainerRepository,
179→        trainerStudentRepository: TrainerStudentRepository,
180→        authRepository: AuthenticationRepository,
181→        featureFlagChecker: FeatureFlagChecking
182→    ) {
183→        self.trainerRepository = trainerRepository
184→        self.trainerStudentRepository = trainerStudentRepository
185→        self.authRepository = authRepository
186→        self.featureFlagChecker = featureFlagChecker
187→    }
188→
189→    func execute() async throws -> (trainer: PersonalTrainer, relationship: TrainerStudentRelationship)? {
190→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
191→            return nil
192→        }
193→
194→        guard let currentUser = try await authRepository.currentUser() else {
195→            return nil
196→        }
197→
198→        guard let relationship = try await trainerStudentRepository.getCurrentRelationship(studentId: currentUser.id) else {
199→            return nil
200→        }
201→
202→        guard relationship.status == .active || relationship.status == .pending else {
203→            return nil
204→        }
205→
206→        guard let trainer = try? await trainerRepository.fetchTrainer(id: relationship.trainerId) else {
207→            return nil
208→        }
209→
210→        return (trainer, relationship)
211→    }
212→
213→    func observeRelationship() -> AsyncStream<TrainerStudentRelationship?> {
214→        AsyncStream { continuation in
215→            Task {
216→                guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
217→                    continuation.yield(nil)
218→                    continuation.finish()
219→                    return
220→                }
221→
222→                guard let currentUser = try? await authRepository.currentUser() else {
223→                    continuation.yield(nil)
224→                    continuation.finish()
225→                    return
226→                }
227→
228→                for await relationship in trainerStudentRepository.observeRelationship(studentId: currentUser.id) {
229→                    continuation.yield(relationship)
230→                }
231→
232→                continuation.finish()
233→            }
234→        }
235→    }
236→}
