 55→    private func checkOperationalFlags() async {
 56→        guard let featureFlags = resolver.resolve(FeatureFlagChecking.self) else { return }
 57→        try? await featureFlags.refreshFlags()
 58→        isMaintenanceMode = await featureFlags.isFeatureEnabled(.maintenanceModeEnabled)
 59→        isForceUpdateRequired = await featureFlags.isFeatureEnabled(.forceUpdateEnabled)
 60→    }
 61→
 62→    private func tabView(for tab: AppTab, @ViewBuilder content: () -> some View) -> some View {
 63→        NavigationStack(path: pathBinding(for: tab)) {
 64→            content()
 65→                .navigationDestination(for: AppRoute.self) { route in
 66→                    routeDestination(for: route)
 67→                }
 68→        }
 69→        .tabItem {
 70→            // Icon-only tab items (no labels)
 71→            Image(systemName: tab.systemImage)
 72→        }
 73→        .tag(tab)
 74→    }
 75→
 76→    private func pathBinding(for tab: AppTab) -> Binding<NavigationPath> {
 77→        Binding(
 78→            get: { router.tabPaths[tab] ?? NavigationPath() },
 79→            set: { router.tabPaths[tab] = $0 }
 80→        )
 81→    }
 82→
 83→    @ViewBuilder
 84→    private func routeDestination(for route: AppRoute) -> some View {
 85→        switch route {
 86→        case .onboarding:
 87→            OnboardingFlowView(resolver: resolver, isEditing: false) {
 88→                // Pop da tab atual (pode ser home ou profile)
 89→                router.pop(on: router.selectedTab)
 90→            }
 91→        case .editProfile:
 92→            OnboardingFlowView(resolver: resolver, isEditing: true) {
 93→                // Pop da tab atual
 94→                router.pop(on: router.selectedTab)
 95→            }
 96→        case .setup:
 97→            PlaceholderView(
 98→                title: "Setup Inicial",
 99→                message: "Stepper com 6 perguntas será implementado aqui."
100→            )
101→        case .workoutPlan:
102→            WorkoutPlanView()
103→        case .exerciseDetail:
104→            WorkoutExerciseDetailView()
105→        case .workoutExecution:
106→            WorkoutExecutionView()
107→        case .workoutExercisePreview(let prescription):
108→            WorkoutExercisePreviewView(prescription: prescription)
109→        case .workoutSummary:
110→            WorkoutCompletionView()
111→        case .paywall:
112→            if let repo = resolver.resolve(EntitlementRepository.self) as? StoreKitEntitlementRepository {
113→                OptimizedPaywallView(storeService: repo.service) {
114→                    // On purchase success, generate workout
115→                    if let planId = sessionStore.plan?.id {
116→                        router.pop(on: .home) // Pop paywall
117→                        router.push(.workoutPlan(planId), on: .home)
118→                    } else {
119→                        router.pop(on: .home)
120→                    }
121→                } onDismiss: {
122→                    router.pop(on: .home)
123→                }
124→            } else {
125→                PlaceholderView(
126→                    title: "Paywall Pro",
127→                    message: "Erro ao carregar paywall."
128→                )
129→            }
130→        case .programDetail(let programId):
131→            ProgramDetailView(programId: programId, resolver: resolver)
