  1→//
  2→//  FirebasePersonalTrainerRepository.swift
  3→//  FitToday
  4→//
  5→//  Created by Claude on 04/02/26.
  6→//
  7→
  8→import Foundation
  9→
 10→// MARK: - Firebase Personal Trainer Repository
 11→
 12→/// Implementation of personal trainer and trainer-student repositories.
 13→///
 14→/// Uses `CMSTrainerService` for connection API calls (POST/GET connect)
 15→/// and `FirebasePersonalTrainerService` for real-time observation.
 16→final class FirebasePersonalTrainerRepository: PersonalTrainerRepository, TrainerStudentRepository, @unchecked Sendable {
 17→
 18→    private let service: FirebasePersonalTrainerService
 19→    private let cmsService: CMSTrainerService?
 20→
 21→    // MARK: - Initialization
 22→
 23→    init(
 24→        service: FirebasePersonalTrainerService = FirebasePersonalTrainerService(),
 25→        cmsService: CMSTrainerService? = nil
 26→    ) {
 27→        self.service = service
 28→        self.cmsService = cmsService
 29→    }
 30→
 31→    // MARK: - PersonalTrainerRepository
 32→
 33→    func fetchTrainer(id: String) async throws -> PersonalTrainer {
 34→        do {
 35→            let fbTrainer = try await service.fetchTrainer(id: id)
 36→            return PersonalTrainerMapper.toDomain(fbTrainer, id: id)
 37→        } catch let error as NSError {
 38→            if error.code == 404 {
 39→                throw DomainError.notFound(resource: "Personal Trainer")
 40→            }
 41→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 42→        }
 43→    }
 44→
 45→    func searchTrainers(query: String, limit: Int) async throws -> [PersonalTrainer] {
 46→        do {
 47→            let results = try await service.searchTrainers(query: query, limit: limit)
 48→            return results.map { PersonalTrainerMapper.toDomain($0.1, id: $0.0) }
 49→        } catch {
 50→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 51→        }
 52→    }
 53→
 54→    func findByInviteCode(_ code: String) async throws -> PersonalTrainer? {
 55→        do {
 56→            guard let result = try await service.findByInviteCode(code) else {
 57→                return nil
 58→            }
 59→            return PersonalTrainerMapper.toDomain(result.1, id: result.0)
 60→        } catch {
 61→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 62→        }
 63→    }
 64→
 65→    // MARK: - TrainerStudentRepository
 66→
 67→    func requestConnection(
 68→        trainerId: String,
 69→        studentId: String,
 70→        studentDisplayName: String
 71→    ) async throws -> String {
 72→        guard let cmsService else {
 73→            throw DomainError.repositoryFailure(reason: "CMS service not available")
 74→        }
 75→
 76→        do {
 77→            let request = CMSConnectionRequest(
 78→                studentId: studentId,
 79→                studentName: studentDisplayName
 80→            )
 81→            let response = try await cmsService.requestConnection(
 82→                trainerId: trainerId,
 83→                connection: request
 84→            )
 85→            return response.id
 86→        } catch let error as CMSServiceError {
 87→            switch error {
 88→            case .unexpectedStatus(409):
 89→                throw DomainError.invalidInput(reason: "Connection already exists with this trainer")
 90→            default:
 91→                throw DomainError.repositoryFailure(reason: error.localizedDescription)
 92→            }
 93→        } catch {
 94→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 95→        }
 96→    }
 97→
 98→    func cancelConnection(relationshipId: String) async throws {
 99→        do {
100→            try await service.cancelConnection(relationshipId: relationshipId)
101→        } catch {
102→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
103→        }
104→    }
105→
106→    func getCurrentRelationship(studentId: String) async throws -> TrainerStudentRelationship? {
107→        do {
108→            guard let result = try await service.getCurrentRelationship(studentId: studentId) else {
109→                return nil
110→            }
111→            return PersonalTrainerMapper.toRelationship(result.1, id: result.0)
112→        } catch {
113→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
114→        }
115→    }
116→
117→    func observeRelationship(studentId: String) -> AsyncStream<TrainerStudentRelationship?> {
118→        AsyncStream { continuation in
119→            Task {
120→                let stream = await service.observeRelationship(studentId: studentId)
121→                for await result in stream {
122→                    if let (id, fbRelationship) = result {
123→                        let relationship = PersonalTrainerMapper.toRelationship(fbRelationship, id: id)
124→                        continuation.yield(relationship)
125→                    } else {
126→                        continuation.yield(nil)
127→                    }
128→                }
129→                continuation.finish()
130→            }
131→        }
132→    }
133→}
134→

  1→//
  2→//  PersonalTrainerUseCases.swift
  3→//  FitToday
  4→//
  5→//  Created by AI on 04/02/26.
  6→//
  7→
  8→import Foundation
  9→
 10→// MARK: - Errors
 11→
 12→enum PersonalTrainerError: LocalizedError {
 13→    case featureDisabled
 14→    case trainerNotFound
 15→    case invalidInviteCode
 16→    case alreadyConnected
 17→    case connectionNotFound
 18→    case unauthorized
 19→    case networkError(underlying: Error)
 20→
 21→    var errorDescription: String? {
 22→        switch self {
 23→        case .featureDisabled:
 24→            return "Esta funcionalidade ainda nao esta disponivel."
 25→        case .trainerNotFound:
 26→            return "Personal trainer nao encontrado."
 27→        case .invalidInviteCode:
 28→            return "Codigo de convite invalido ou expirado."
 29→        case .alreadyConnected:
 30→            return "Voce ja esta conectado a um personal trainer."
 31→        case .connectionNotFound:
 32→            return "Conexao nao encontrada."
 33→        case .unauthorized:
 34→            return "Voce precisa estar logado para usar esta funcionalidade."
 35→        case .networkError(let error):
 36→            return "Erro de conexao: \(error.localizedDescription)"
 37→        }
 38→    }
 39→}
 40→
 41→// MARK: - Discover Trainers Use Case
 42→
 43→protocol DiscoverTrainersUseCaseProtocol: Sendable {
 44→    func searchByName(_ query: String, limit: Int) async throws -> [PersonalTrainer]
 45→    func findByInviteCode(_ code: String) async throws -> PersonalTrainer?
 46→}
 47→
 48→final class DiscoverTrainersUseCase: DiscoverTrainersUseCaseProtocol, @unchecked Sendable {
 49→    private let repository: PersonalTrainerRepository
 50→    private let featureFlagChecker: FeatureFlagChecking
 51→
 52→    init(repository: PersonalTrainerRepository, featureFlagChecker: FeatureFlagChecking) {
 53→        self.repository = repository
 54→        self.featureFlagChecker = featureFlagChecker
 55→    }
 56→
 57→    func searchByName(_ query: String, limit: Int = 20) async throws -> [PersonalTrainer] {
 58→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
 59→            throw PersonalTrainerError.featureDisabled
 60→        }
 61→
 62→        let trimmedQuery = query.trimmingCharacters(in: .whitespacesAndNewlines)
 63→        let trainers = try await repository.searchTrainers(query: trimmedQuery, limit: limit)
 64→
 65→        // Sort by rating (highest first) for discovery
 66→        return trainers.sorted { ($0.rating ?? 0) > ($1.rating ?? 0) }
 67→    }
 68→
 69→    func findByInviteCode(_ code: String) async throws -> PersonalTrainer? {
 70→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
 71→            throw PersonalTrainerError.featureDisabled
 72→        }
 73→
 74→        let trimmedCode = code.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
 75→        guard !trimmedCode.isEmpty else {
 76→            return nil
 77→        }
 78→
 79→        return try await repository.findByInviteCode(trimmedCode)
 80→    }
 81→}
 82→
 83→// MARK: - Request Trainer Connection Use Case
 84→
 85→protocol RequestTrainerConnectionUseCaseProtocol: Sendable {
 86→    func execute(trainerId: String) async throws -> String
 87→}
 88→
 89→final class RequestTrainerConnectionUseCase: RequestTrainerConnectionUseCaseProtocol, @unchecked Sendable {
 90→    private let trainerStudentRepository: TrainerStudentRepository
 91→    private let authRepository: AuthenticationRepository
 92→    private let featureFlagChecker: FeatureFlagChecking
 93→
 94→    init(
 95→        trainerStudentRepository: TrainerStudentRepository,
 96→        authRepository: AuthenticationRepository,
 97→        featureFlagChecker: FeatureFlagChecking
 98→    ) {
 99→        self.trainerStudentRepository = trainerStudentRepository
100→        self.authRepository = authRepository
101→        self.featureFlagChecker = featureFlagChecker
102→    }
103→
104→    func execute(trainerId: String) async throws -> String {
105→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
106→            throw PersonalTrainerError.featureDisabled
107→        }
108→
109→        guard let currentUser = try await authRepository.currentUser() else {
110→            throw PersonalTrainerError.unauthorized
111→        }
112→
113→        // Check if already has an active connection
114→        if let existingRelationship = try await trainerStudentRepository.getCurrentRelationship(studentId: currentUser.id) {
115→            if existingRelationship.status == .active || existingRelationship.status == .pending {
116→                throw PersonalTrainerError.alreadyConnected
117→            }
118→        }
119→
120→        let relationshipId = try await trainerStudentRepository.requestConnection(
121→            trainerId: trainerId,
122→            studentId: currentUser.id,
123→            studentDisplayName: currentUser.displayName
124→        )
125→
126→        return relationshipId
127→    }
128→}
129→
130→// MARK: - Cancel Trainer Connection Use Case
131→
132→protocol CancelTrainerConnectionUseCaseProtocol: Sendable {
133→    func execute(relationshipId: String) async throws
134→}
135→
136→final class CancelTrainerConnectionUseCase: CancelTrainerConnectionUseCaseProtocol, @unchecked Sendable {
137→    private let trainerStudentRepository: TrainerStudentRepository
138→    private let authRepository: AuthenticationRepository
139→    private let featureFlagChecker: FeatureFlagChecking
140→
141→    init(
142→        trainerStudentRepository: TrainerStudentRepository,
143→        authRepository: AuthenticationRepository,
144→        featureFlagChecker: FeatureFlagChecking
145→    ) {
146→        self.trainerStudentRepository = trainerStudentRepository
147→        self.authRepository = authRepository
148→        self.featureFlagChecker = featureFlagChecker
149→    }
150→
151→    func execute(relationshipId: String) async throws {
152→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
153→            throw PersonalTrainerError.featureDisabled
154→        }
155→
156→        guard try await authRepository.currentUser() != nil else {
157→            throw PersonalTrainerError.unauthorized
158→        }
159→
160→        try await trainerStudentRepository.cancelConnection(relationshipId: relationshipId)
161→    }
162→}
163→
164→// MARK: - Get Current Trainer Use Case
165→
166→protocol GetCurrentTrainerUseCaseProtocol: Sendable {
167→    func execute() async throws -> (trainer: PersonalTrainer, relationship: TrainerStudentRelationship)?
168→    func observeRelationship() -> AsyncStream<TrainerStudentRelationship?>
169→}
170→
171→final class GetCurrentTrainerUseCase: GetCurrentTrainerUseCaseProtocol, @unchecked Sendable {
172→    private let trainerRepository: PersonalTrainerRepository
173→    private let trainerStudentRepository: TrainerStudentRepository
174→    private let authRepository: AuthenticationRepository
175→    private let featureFlagChecker: FeatureFlagChecking
176→
177→    init(
178→        trainerRepository: PersonalTrainerRepository,
179→        trainerStudentRepository: TrainerStudentRepository,
180→        authRepository: AuthenticationRepository,
181→        featureFlagChecker: FeatureFlagChecking
182→    ) {
183→        self.trainerRepository = trainerRepository
184→        self.trainerStudentRepository = trainerStudentRepository
185→        self.authRepository = authRepository
186→        self.featureFlagChecker = featureFlagChecker
187→    }
188→
189→    func execute() async throws -> (trainer: PersonalTrainer, relationship: TrainerStudentRelationship)? {
190→        guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
191→            return nil
192→        }
193→
194→        guard let currentUser = try await authRepository.currentUser() else {
195→            return nil
196→        }
197→
198→        guard let relationship = try await trainerStudentRepository.getCurrentRelationship(studentId: currentUser.id) else {
199→            return nil
200→        }
201→
202→        guard relationship.status == .active || relationship.status == .pending else {
203→            return nil
204→        }
205→
206→        guard let trainer = try? await trainerRepository.fetchTrainer(id: relationship.trainerId) else {
207→            return nil
208→        }
209→
210→        return (trainer, relationship)
211→    }
212→
213→    func observeRelationship() -> AsyncStream<TrainerStudentRelationship?> {
214→        AsyncStream { continuation in
215→            Task {
216→                guard await featureFlagChecker.isFeatureEnabled(.personalTrainerEnabled) else {
217→                    continuation.yield(nil)
218→                    continuation.finish()
219→                    return
220→                }
221→
222→                guard let currentUser = try? await authRepository.currentUser() else {
223→                    continuation.yield(nil)
224→                    continuation.finish()
225→                    return
226→                }
227→
228→                for await relationship in trainerStudentRepository.observeRelationship(studentId: currentUser.id) {
229→                    continuation.yield(relationship)
230→                }
231→
232→                continuation.finish()
233→            }
234→        }
235→    }
236→}
237→
238→// MARK: - Fetch Assigned Workouts Use Case
239→
240→protocol FetchAssignedWorkoutsUseCaseProtocol: Sendable {
241→    func execute() async throws -> [TrainerWorkout]
242→    func observe() -> AsyncStream<[TrainerWorkout]>
243→}
244→
245→final class FetchAssignedWorkoutsUseCase: FetchAssignedWorkoutsUseCaseProtocol, @unchecked Sendable {
246→    private let trainerWorkoutRepository: TrainerWorkoutRepository
247→    private let authRepository: AuthenticationRepository
248→    private let featureFlagChecker: FeatureFlagChecking
249→
250→    init(
251→        trainerWorkoutRepository: TrainerWorkoutRepository,
252→        authRepository: AuthenticationRepository,
253→        featureFlagChecker: FeatureFlagChecking
254→    ) {
255→        self.trainerWorkoutRepository = trainerWorkoutRepository
256→        self.authRepository = authRepository
257→        self.featureFlagChecker = featureFlagChecker
258→    }
259→
260→    func execute() async throws -> [TrainerWorkout] {
261→        guard await featureFlagChecker.isFeatureEnabled(.cmsWorkoutSyncEnabled) else {
262→            return []
263→        }
264→
265→        guard let currentUser = try await authRepository.currentUser() else {
266→            return []
267→        }
268→
269→        return try await trainerWorkoutRepository.fetchAssignedWorkouts(studentId: currentUser.id)
270→    }
271→
272→    func observe() -> AsyncStream<[TrainerWorkout]> {
273→        AsyncStream { continuation in
274→            Task {
275→                guard await featureFlagChecker.isFeatureEnabled(.cmsWorkoutSyncEnabled) else {
276→                    continuation.yield([])
277→                    continuation.finish()
278→                    return
279→                }
280→
281→                guard let currentUser = try? await authRepository.currentUser() else {
282→                    continuation.yield([])
283→                    continuation.finish()
284→                    return
285→                }
286→
287→                for await workouts in trainerWorkoutRepository.observeAssignedWorkouts(studentId: currentUser.id) {
288→                    continuation.yield(workouts)
289→                }
290→
291→                continuation.finish()
292→            }
293→        }
294→    }
295→}
