  2→//  FirebasePersonalTrainerRepository.swift
  3→//  FitToday
  4→//
  5→//  Created by Claude on 04/02/26.
  6→//
  7→
  8→import Foundation
  9→
 10→// MARK: - Firebase Personal Trainer Repository
 11→
 12→/// Implementation of personal trainer and trainer-student repositories.
 13→///
 14→/// Uses `CMSTrainerService` for connection API calls (POST/GET connect)
 15→/// and `FirebasePersonalTrainerService` for real-time observation.
 16→final class FirebasePersonalTrainerRepository: PersonalTrainerRepository, TrainerStudentRepository, @unchecked Sendable {
 17→
 18→    private let service: FirebasePersonalTrainerService
 19→    private let cmsService: CMSTrainerService?
 20→
 21→    // MARK: - Initialization
 22→
 23→    init(
 24→        service: FirebasePersonalTrainerService = FirebasePersonalTrainerService(),
 25→        cmsService: CMSTrainerService? = nil
 26→    ) {
 27→        self.service = service
 28→        self.cmsService = cmsService
 29→    }
 30→
 31→    // MARK: - PersonalTrainerRepository
 32→
 33→    func fetchTrainer(id: String) async throws -> PersonalTrainer {
 34→        do {
 35→            let fbTrainer = try await service.fetchTrainer(id: id)
 36→            return PersonalTrainerMapper.toDomain(fbTrainer, id: id)
 37→        } catch let error as NSError {
 38→            if error.code == 404 {
 39→                throw DomainError.notFound(resource: "Personal Trainer")
 40→            }
 41→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 42→        }
 43→    }
 44→
 45→    func searchTrainers(query: String, limit: Int) async throws -> [PersonalTrainer] {
 46→        do {
 47→            let results = try await service.searchTrainers(query: query, limit: limit)
 48→            return results.map { PersonalTrainerMapper.toDomain($0.1, id: $0.0) }
 49→        } catch {
 50→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 51→        }
 52→    }
 53→
 54→    func findByInviteCode(_ code: String) async throws -> PersonalTrainer? {
 55→        do {
 56→            guard let result = try await service.findByInviteCode(code) else {
 57→                return nil
 58→            }
 59→            return PersonalTrainerMapper.toDomain(result.1, id: result.0)
 60→        } catch {
 61→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 62→        }
 63→    }
 64→
 65→    // MARK: - TrainerStudentRepository
 66→
 67→    func requestConnection(
 68→        trainerId: String,
 69→        studentId: String,
 70→        studentDisplayName: String
 71→    ) async throws -> String {
 72→        guard let cmsService else {
 73→            throw DomainError.repositoryFailure(reason: "CMS service not available")
 74→        }
 75→
 76→        do {
 77→            let request = CMSConnectionRequest(
 78→                studentId: studentId,
 79→                studentName: studentDisplayName
 80→            )
 81→            let response = try await cmsService.requestConnection(
 82→                trainerId: trainerId,
 83→                connection: request
 84→            )
 85→            return response.id
 86→        } catch let error as CMSServiceError {
 87→            switch error {
 88→            case .unexpectedStatus(409):
 89→                throw DomainError.invalidInput(reason: "Connection already exists with this trainer")
 90→            default:
 91→                throw DomainError.repositoryFailure(reason: error.localizedDescription)
 92→            }
 93→        } catch {
 94→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 95→        }
 96→    }
 97→
 98→    func cancelConnection(relationshipId: String) async throws {
 99→        do {
100→            try await service.cancelConnection(relationshipId: relationshipId)
101→        } catch {
102→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
103→        }
104→    }
105→
106→    func getCurrentRelationship(studentId: String) async throws -> TrainerStudentRelationship? {
107→        do {
108→            guard let result = try await service.getCurrentRelationship(studentId: studentId) else {
109→                return nil
110→            }
111→            return PersonalTrainerMapper.toRelationship(result.1, id: result.0)
112→        } catch {
113→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
114→        }
115→    }
116→
117→    func observeRelationship(studentId: String) -> AsyncStream<TrainerStudentRelationship?> {
118→        AsyncStream { continuation in
119→            Task {
120→                let stream = await service.observeRelationship(studentId: studentId)
121→                for await result in stream {
122→                    if let (id, fbRelationship) = result {
123→                        let relationship = PersonalTrainerMapper.toRelationship(fbRelationship, id: id)
124→                        continuation.yield(relationship)
125→                    } else {
126→                        continuation.yield(nil)
127→                    }
128→                }
129→                continuation.finish()
130→            }
131→        }
132→    }
133→}
